def parse_csv(text: str) -> list[list[str]]:
    records = []
    current_record = []
    current_field = ""
    in_quotes = False
    i = 0
    n = len(text)

    while i < n:
        char = text[i]

        if in_quotes:
            if char == '"':
                if i + 1 < n and text[i+1] == '"':
                    current_field += '"'
                    i += 1
                else:
                    in_quotes = False
                    if i + 1 < n:
                        next_char = text[i+1]
                        if next_char == ',':
                            current_record.append(current_field)
                            current_field = ""
                            i += 1
                        elif next_char == '\r':
                            if i + 2 < n and text[i+2] == '\n':
                                i += 2
                            else:
                                i += 1
                            current_record.append(current_field)
                            records.append(current_record)
                            current_record = []
                            current_field = ""
                            continue
                        elif next_char == '\n':
                            i += 1
                            current_record.append(current_field)
                            records.append(current_record)
                            current_record = []
                            current_field = ""
                            continue
                        else:
                            raise ValueError(f"Invalid character '{next_char}' after closing quote")
                    else:
                        current_record.append(current_field)
                        records.append(current_record)
                        current_record = []
                        current_field = ""
            else:
                current_field += char
        else:
            if char == '"':
                in_quotes = True
            elif char == ',':
                current_record.append(current_field)
                current_field = ""
            elif char == '\r':
                if i + 1 < n and text[i+1] == '\n':
                    i += 1
                current_record.append(current_field)
                records.append(current_record)
                current_record = []
                current_field = ""
                continue
            elif char == '\n':
                current_record.append(current_field)
                records.append(current_record)
                current_record = []
                current_field = ""
            else:
                current_field += char
        i += 1

    if in_quotes:
        raise ValueError("Unclosed quote")

    if current_field or current_record:
        current_record.append(current_field)
        if current_record:
            records.append(current_record)

    return records
